import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import Navbar from '../../components/Navbar';
import Footer from '../../components/Footer';
import API from '../../services/api';
import './AdminDashboard.css';

const AdminDashboard = () => {
  const { user } = useAuth();
  const [stats, setStats] = useState({
    totalUsers: 0,
    totalProperties: 0,
    pendingProperties: 0,
    totalAgents: 0
  });
  const [pendingProperties, setPendingProperties] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      
      // Fetch all properties (including unapproved)
      const propertiesRes = await API.get('/properties?isApproved=false');
      const pending = propertiesRes.data.data;
      
      // Fetch all users
      const usersRes = await API.get('/users');
      const users = usersRes.data.data;
      
      setPendingProperties(pending);
      
      setStats({
        totalUsers: users.length,
        totalProperties: propertiesRes.data.total,
        pendingProperties: pending.length,
        totalAgents: users.filter(u => u.role === 'agent').length
      });
    } catch (error) {
      console.error('Error fetching dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (propertyId) => {
    if (window.confirm('Approve this property?')) {
      try {
        await API.put(`/properties/${propertyId}/approve`);
        alert('Property approved successfully!');
        fetchDashboardData();
      } catch (error) {
        alert('Error approving property: ' + (error.response?.data?.message || error.message));
      }
    }
  };

  const handleReject = async (propertyId) => {
    if (window.confirm('Delete this property? This action cannot be undone.')) {
      try {
        await API.delete(`/properties/${propertyId}`);
        alert('Property rejected and deleted');
        fetchDashboardData();
      } catch (error) {
        alert('Error rejecting property: ' + (error.response?.data?.message || error.message));
      }
    }
  };

  return (
    <div className="admin-dashboard">
      <Navbar />
      
      <div className="dashboard-container">
        <div className="container">
          {/* Header */}
          <div className="dashboard-header">
            <div>
              <h1>Admin Dashboard</h1>
              <p>Welcome, {user?.name}! You have full control 👑</p>
            </div>
            <div className="header-actions">
              <Link to="/admin/users" className="btn-secondary">
                Manage Users
              </Link>
            </div>
          </div>

          {/* Stats Grid */}
          <div className="admin-stats-grid">
            <div className="admin-stat-card users">
              <div className="stat-icon">👥</div>
              <div className="stat-content">
                <div className="stat-number">{stats.totalUsers}</div>
                <div className="stat-label">Total Users</div>
              </div>
            </div>

            <div className="admin-stat-card properties">
              <div className="stat-icon">🏠</div>
              <div className="stat-content">
                <div className="stat-number">{stats.totalProperties}</div>
                <div className="stat-label">Total Properties</div>
              </div>
            </div>

            <div className="admin-stat-card pending">
              <div className="stat-icon">⏳</div>
              <div className="stat-content">
                <div className="stat-number">{stats.pendingProperties}</div>
                <div className="stat-label">Pending Approval</div>
              </div>
            </div>

            <div className="admin-stat-card agents">
              <div className="stat-icon">👨‍💼</div>
              <div className="stat-content">
                <div className="stat-number">{stats.totalAgents}</div>
                <div className="stat-label">Active Agents</div>
              </div>
            </div>
          </div>

          {/* Pending Properties */}
          <div className="pending-section">
            <h2>Pending Property Approvals</h2>
            
            {loading ? (
              <div className="loading">
                <div className="loader"></div>
                <p>Loading pending properties...</p>
              </div>
            ) : pendingProperties.length === 0 ? (
              <div className="empty-state">
                <div className="empty-icon">✅</div>
                <h3>All Caught Up!</h3>
                <p>No properties pending approval</p>
              </div>
            ) : (
              <div className="pending-properties-grid">
                {pendingProperties.map((property) => (
                  <div key={property._id} className="pending-property-card">
                    <div className="property-image">
                      {property.images && property.images.length > 0 ? (
                        <img src={property.images[0].url} alt={property.title} />
                      ) : (
                        <div className="no-image">No Image</div>
                      )}
                    </div>
                    
                    <div className="property-details">
                      <h3>{property.title}</h3>
                      <p className="location">📍 {property.location.city}, {property.location.state}</p>
                      <p className="price">${property.price.toLocaleString()}</p>
                      
                      <div className="property-features-mini">
                        <span>🛏️ {property.features.bedrooms} Beds</span>
                        <span>🚿 {property.features.bathrooms} Baths</span>
                        <span>📏 {property.features.area} sqft</span>
                      </div>

                      <div className="agent-info-mini">
                        <p>👨‍💼 Agent: {property.agent?.name || 'Unknown'}</p>
                      </div>

                      <div className="approval-actions">
                        <Link 
                          to={`/property/${property._id}`}
                          className="btn-view-detail"
                        >
                          👁️ View Details
                        </Link>
                        <button 
                          onClick={() => handleApprove(property._id)}
                          className="btn-approve"
                        >
                          ✅ Approve
                        </button>
                        <button 
                          onClick={() => handleReject(property._id)}
                          className="btn-reject"
                        >
                          ❌ Reject
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
};

export default AdminDashboard;
